// Trigger-alignment prelude for the determinism check.
// The two ensures-conjuncts (one for `post1_self_/r1` and one for `post2_self_/r2`)
// each carry several `forall|x| ... post_self_.foo(x) ...` clauses whose triggers
// mention different post-state instances, so z3 never lines them up.
// We re-assert each forall for *both* runs (closing the trigger gap) and then do
// pointwise reasoning that forces the two post-states to agree on every accessor.

let oc = pre_self_.get_proc(target_proc_ptr).owning_container;
let src_pa = pre_self_.get_address_space(src_proc_ptr)[src_va].addr;

// --- Re-pull the per-run ensures so triggers fire under both post-states. ---

assert(forall|p_ptr: ProcPtr|
    #![auto]
    post1_self_.proc_dom().contains(p_ptr)
        ==> post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
assert(forall|p_ptr: ProcPtr|
    #![auto]
    post2_self_.proc_dom().contains(p_ptr)
        ==> post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));

assert(forall|p_ptr: ProcPtr|
    #![auto]
    post1_self_.proc_dom().contains(p_ptr) && p_ptr != target_proc_ptr
        ==> post1_self_.get_address_space(p_ptr) =~= pre_self_.get_address_space(p_ptr));
assert(forall|p_ptr: ProcPtr|
    #![auto]
    post2_self_.proc_dom().contains(p_ptr) && p_ptr != target_proc_ptr
        ==> post2_self_.get_address_space(p_ptr) =~= pre_self_.get_address_space(p_ptr));

assert(forall|t_ptr: ThreadPtr|
    #![auto]
    post1_self_.thread_dom().contains(t_ptr)
        ==> post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
assert(forall|t_ptr: ThreadPtr|
    #![auto]
    post2_self_.thread_dom().contains(t_ptr)
        ==> post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));

assert(forall|c_ptr: ContainerPtr|
    #![auto]
    post1_self_.container_dom().contains(c_ptr)
        && c_ptr != post1_self_.get_proc(target_proc_ptr).owning_container
        ==> post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
assert(forall|c_ptr: ContainerPtr|
    #![auto]
    post2_self_.container_dom().contains(c_ptr)
        && c_ptr != post2_self_.get_proc(target_proc_ptr).owning_container
        ==> post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));

assert(forall|e_ptr: EndpointPtr|
    #![auto]
    post1_self_.endpoint_dom().contains(e_ptr)
        ==> post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
assert(forall|e_ptr: EndpointPtr|
    #![auto]
    post2_self_.endpoint_dom().contains(e_ptr)
        ==> post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));

assert(forall|c: ContainerPtr|
    #![auto]
    post1_self_.container_dom().contains(c)
        ==> post1_self_.get_container_owned_pages(c)
            =~= pre_self_.get_container_owned_pages(c));
assert(forall|c: ContainerPtr|
    #![auto]
    post2_self_.container_dom().contains(c)
        ==> post2_self_.get_container_owned_pages(c)
            =~= pre_self_.get_container_owned_pages(c));

assert(forall|p: PagePtr|
    #![trigger post1_self_.page_alloc.page_is_mapped(p)]
    post1_self_.page_alloc.page_is_mapped(p) == pre_self_.page_alloc.page_is_mapped(p));
assert(forall|p: PagePtr|
    #![trigger post2_self_.page_alloc.page_is_mapped(p)]
    post2_self_.page_alloc.page_is_mapped(p) == pre_self_.page_alloc.page_is_mapped(p));

assert(forall|page_ptr: PagePtr|
    #![trigger post1_self_.page_mapping@[page_ptr]]
    pre_self_.page_mapping@.dom().contains(page_ptr) && page_ptr != src_pa
        ==> pre_self_.page_mapping@[page_ptr] == post1_self_.page_mapping@[page_ptr]);
assert(forall|page_ptr: PagePtr|
    #![trigger post2_self_.page_mapping@[page_ptr]]
    pre_self_.page_mapping@.dom().contains(page_ptr) && page_ptr != src_pa
        ==> pre_self_.page_mapping@[page_ptr] == post2_self_.page_mapping@[page_ptr]);

assert(forall|va: VAddr|
    #![auto]
    va != target_va && pre_self_.get_address_space(target_proc_ptr).dom().contains(va)
        ==> post1_self_.get_address_space(target_proc_ptr)[va]
            == pre_self_.get_address_space(target_proc_ptr)[va]);
assert(forall|va: VAddr|
    #![auto]
    va != target_va && pre_self_.get_address_space(target_proc_ptr).dom().contains(va)
        ==> post2_self_.get_address_space(target_proc_ptr)[va]
            == pre_self_.get_address_space(target_proc_ptr)[va]);

// --- Pointwise equalities of post1 vs post2 on every accessor. ---

assert(post1_self_.proc_dom() == post2_self_.proc_dom());
assert(post1_self_.thread_dom() == post2_self_.thread_dom());
assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());
assert(post1_self_.container_dom() == post2_self_.container_dom());

assert(oc == post1_self_.get_proc(target_proc_ptr).owning_container);
assert(oc == post2_self_.get_proc(target_proc_ptr).owning_container);

assert forall|p_ptr: ProcPtr|
    post1_self_.proc_dom().contains(p_ptr) implies
    post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
    // Both =~= pre.get_proc(p_ptr).
}

assert forall|p_ptr: ProcPtr|
    post1_self_.proc_dom().contains(p_ptr) implies
    post1_self_.get_address_space(p_ptr) =~= post2_self_.get_address_space(p_ptr) by {
    if p_ptr == target_proc_ptr {
        // Both equal pre.get_address_space(target).insert(target_va, pre.get_address_space(src)[src_va]).
        assert(post1_self_.get_address_space(target_proc_ptr)
            =~= pre_self_.get_address_space(target_proc_ptr)
                .insert(target_va, pre_self_.get_address_space(src_proc_ptr)[src_va]));
        assert(post2_self_.get_address_space(target_proc_ptr)
            =~= pre_self_.get_address_space(target_proc_ptr)
                .insert(target_va, pre_self_.get_address_space(src_proc_ptr)[src_va]));
    } else {
        // Both equal pre.get_address_space(p_ptr).
    }
}

assert forall|t_ptr: ThreadPtr|
    post1_self_.thread_dom().contains(t_ptr) implies
    post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
    // Both =~= pre.get_thread(t_ptr).
}

assert forall|e_ptr: EndpointPtr|
    post1_self_.endpoint_dom().contains(e_ptr) implies
    post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {
    // Both =~= pre.get_endpoint(e_ptr).
}

assert forall|c: ContainerPtr|
    post1_self_.container_dom().contains(c) implies
    post1_self_.get_container_owned_pages(c)
        =~= post2_self_.get_container_owned_pages(c) by {
    // Both =~= pre.get_container_owned_pages(c).
}

assert forall|c_ptr: ContainerPtr|
    post1_self_.container_dom().contains(c_ptr) && c_ptr != oc implies
    post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {
    // Both =~= pre.get_container(c_ptr).
}

// page_alloc.page_is_mapped agrees pointwise.
assert forall|p: PagePtr|
    #![trigger post1_self_.page_alloc.page_is_mapped(p), post2_self_.page_alloc.page_is_mapped(p)]
    post1_self_.page_alloc.page_is_mapped(p) == post2_self_.page_alloc.page_is_mapped(p) by {
    // Each side equals pre.page_alloc.page_is_mapped(p).
}

// page_mapping@ extensional equality.
assert(post1_self_.page_mapping@.dom() == pre_self_.page_mapping@.dom());
assert(post2_self_.page_mapping@.dom() == pre_self_.page_mapping@.dom());
assert(post1_self_.page_mapping@.dom() == post2_self_.page_mapping@.dom());

assert forall|page_ptr: PagePtr|
    post1_self_.page_mapping@.dom().contains(page_ptr) implies
    post1_self_.page_mapping@[page_ptr] == post2_self_.page_mapping@[page_ptr] by {
    if page_ptr == src_pa {
        assert(post1_self_.page_mapping@[src_pa]
            == pre_self_.page_mapping@[src_pa].insert((target_proc_ptr, target_va)));
        assert(post2_self_.page_mapping@[src_pa]
            == pre_self_.page_mapping@[src_pa].insert((target_proc_ptr, target_va)));
    } else {
        assert(pre_self_.page_mapping@.dom().contains(page_ptr));
        assert(pre_self_.page_mapping@[page_ptr] == post1_self_.page_mapping@[page_ptr]);
        assert(pre_self_.page_mapping@[page_ptr] == post2_self_.page_mapping@[page_ptr]);
    }
}
assert(post1_self_.page_mapping@ =~= post2_self_.page_mapping@);

// physical_page_reference_counter agrees pointwise on every mapped page.
assert forall|p: PagePtr|
    #![trigger post1_self_.page_alloc.page_is_mapped(p), post2_self_.page_alloc.page_is_mapped(p)]
    post1_self_.page_alloc.page_is_mapped(p) implies
    post1_self_.get_physical_page_reference_counter(p)
        == post2_self_.get_physical_page_reference_counter(p) by {
    if p == src_pa {
        assert(post1_self_.get_physical_page_reference_counter(p)
            == pre_self_.get_physical_page_reference_counter(p) + 1);
        assert(post2_self_.get_physical_page_reference_counter(p)
            == pre_self_.get_physical_page_reference_counter(p) + 1);
    } else {
        assert(post2_self_.page_alloc.page_is_mapped(p));
        assert(post1_self_.get_physical_page_reference_counter(p)
            == pre_self_.get_physical_page_reference_counter(p));
        assert(post2_self_.get_physical_page_reference_counter(p)
            == pre_self_.get_physical_page_reference_counter(p));
    }
}

// num_of_free_pages: both equal pre - r, and both are constrained from below by 0,
// giving r1 == r2 once free_pages_4k lengths agree.
assert(post1_self_.get_num_of_free_pages() == pre_self_.get_num_of_free_pages() - r1);
assert(post2_self_.get_num_of_free_pages() == pre_self_.get_num_of_free_pages() - r2);

// owning_container fields agree.
assert(post1_self_.get_container(oc).owned_procs =~= post2_self_.get_container(oc).owned_procs);
assert(post1_self_.get_container(oc).parent =~= post2_self_.get_container(oc).parent);
assert(post1_self_.get_container(oc).parent_rev_ptr
    =~= post2_self_.get_container(oc).parent_rev_ptr);
assert(post1_self_.get_container(oc).children =~= post2_self_.get_container(oc).children);
assert(post1_self_.get_container(oc).owned_endpoints
    =~= post2_self_.get_container(oc).owned_endpoints);
assert(post1_self_.get_container(oc).owned_threads
    =~= post2_self_.get_container(oc).owned_threads);
assert(post1_self_.get_container(oc).owned_cpus
    =~= post2_self_.get_container(oc).owned_cpus);
assert(post1_self_.get_container(oc).scheduler =~= post2_self_.get_container(oc).scheduler);
